'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/components/auth-provider';
import Image from 'next/image';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Plus, ImageIcon } from 'lucide-react';
import { CharacterModal } from '@/components/character-modal';
import { CharacterFormModal } from '@/components/character-form-modal';

interface Character {
  id: string;
  title: string;
  description: string | null;
  image_url: string | null;
  thumbnail_url: string | null;
  created_at: string;
}

export function CharacterGallery() {
  const { hasPermission } = useAuth();
  const router = useRouter();

  const [characters, setCharacters] = useState<Character[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showFormModal, setShowFormModal] = useState(false);
  const [selectedCharacter, setSelectedCharacter] = useState<Character | null>(null);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const fetchCharacters = useCallback(async () => {
    try {
      const res = await fetch('/api/characters');
      if (res.ok) {
        const data = await res.json();
        setCharacters(data);
      }
    } catch (error) {
      console.error('Failed to fetch characters:', error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCharacters();
  }, [fetchCharacters]);

  const handleAddClick = () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    setShowFormModal(true);
  };

  const handleCharacterClick = (character: Character) => {
    router.push(`/character/${character.id}`);
  };

  const handleFormSuccess = () => {
    fetchCharacters();
    setShowFormModal(false);
  };

  if (isLoading) {
    return (
      <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
        {[...Array(8)].map((_, i) => (
          <Card key={i} className="overflow-hidden">
            <div className="aspect-square bg-muted animate-pulse" />
            <CardContent className="p-4">
              <div className="h-4 bg-muted animate-pulse w-3/4" />
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <>
      {characters.length === 0 ? (
        <Card className="p-12 text-center mt-6 border-0 shadow-none bg-card/60 backdrop-blur-sm">
          <div className="flex flex-col items-center gap-4 text-muted-foreground">
            <ImageIcon className="h-12 w-12" />
            <p>등록된 캐릭터가 없습니다.</p>
          </div>
        </Card>
      ) : (
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 mt-6">
          {characters.map((character) => (
            <Card
              key={character.id}
              className="overflow-hidden cursor-pointer border-0 shadow-none bg-card/60 backdrop-blur-sm hover:bg-card/80 transition-colors group"
              onClick={() => handleCharacterClick(character)}
            >
              <div className="aspect-square relative bg-transparent overflow-hidden">
                {character.thumbnail_url ? (
                  <Image
                    src={character.thumbnail_url}
                    alt={character.title}
                    fill
                    className="object-cover transition-transform duration-300 group-hover:scale-110"
                  />
                ) : (
                  <div className="w-full h-full flex items-center justify-center">
                    <ImageIcon className="h-12 w-12 text-muted-foreground" />
                  </div>
                )}
              </div>
              <CardContent className="p-4">
                <h3 className="font-medium text-foreground truncate text-center">{character.title}</h3>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      

      <CharacterFormModal
        open={showFormModal}
        onOpenChange={setShowFormModal}
        onSuccess={handleFormSuccess}
      />
    </>
  );
}
